evals.prompt:
다음 Go 함수를 더 깔끔하게 리팩토링해주세요. 동작은 유지하고 단일 파일로 출력하세요.

func ProcessOrders(orders []Order) ([]Result, error) {
    var results []Result
    for i := 0; i < len(orders); i++ {
        o := orders[i]
        if o.Status == "pending" {
            if o.Amount > 0 {
                if o.UserID != "" {
                    r := Result{ID: o.ID, Processed: true}
                    results = append(results, r)
                } else {
                    return nil, fmt.Errorf("order %s missing user", o.ID)
                }
            }
        }
    }
    return results, nil
}

type Order struct { ID, UserID, Status string; Amount float64 }
type Result struct { ID string; Processed bool }
